 14→ALFPWorldMapPlayerController::ALFPWorldMapPlayerController()
 15→{
 16→	CameraOffset = FVector::ZeroVector;
 17→
 18→	// 创建世界地图编辑器组件
 19→	WorldMapEditorComponent = CreateDefaultSubobject<ULFPWorldMapEditorComponent>(TEXT("WorldMapEditorComponent"));
 20→}
 21→
 22→void ALFPWorldMapPlayerController::BeginPlay()
 23→{
 24→	Super::BeginPlay();
 25→
 26→	// 设置输入模式
 27→	FInputModeGameAndUI InputMode;
 28→	InputMode.SetLockMouseToViewportBehavior(EMouseLockMode::DoNotLock);
 29→	InputMode.SetHideCursorDuringCapture(false);
 30→	SetInputMode(InputMode);
 31→	bShowMouseCursor = true;
 32→
 33→	// 设置 Enhanced Input
 34→	if (UEnhancedInputLocalPlayerSubsystem* Subsystem = ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer()))
 35→	{
 36→		if (DefaultInputMapping)
 37→		{
 38→			Subsystem->AddMappingContext(DefaultInputMapping, 0);
 39→		}
 40→	}
 41→
 42→	// 场景切换淡入效果
 43→	if (PlayerCameraManager)
 44→	{
 45→		ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
 46→		float FadeDuration = GI ? GI->TransitionFadeDuration : 0.5f;
 47→		PlayerCameraManager->StartCameraFade(1.f, 0.f, FadeDuration, FLinearColor::Black, false, false);
 48→	}
 49→
 50→	// 首帧跳过相机平滑插值
 51→	bSnapCameraNextFrame = true;
 52→}
 53→
 54→void ALFPWorldMapPlayerController::Tick(float DeltaTime)
 55→{
 56→	Super::Tick(DeltaTime);
 57→
 58→	if (bIsDragging)
 59→	{
 60→		DragTime += DeltaTime;
 61→	}
 62→
 63→	// 更新相机位置和旋转
 64→	// 相机位置：CameraOffset（XY 平移）+ CurrentZoom（高度）
 65→	FVector TargetLocation = CameraOffset + FVector(0.f, 0.f, CurrentZoom);
 66→
 67→	// 相机旋转：俯视角
 68→	FRotator TargetRotation(CameraPitchAngle, 0.f, 0.f);
 69→
 70→	// 平滑插值并设置
 71→	FRotator CurrentRotation = GetControlRotation();
 72→	if (bSnapCameraNextFrame)
 73→	{
 74→		SetControlRotation(TargetRotation);
 75→	}
 76→	else
 77→	{
 78→		SetControlRotation(FMath::RInterpTo(CurrentRotation, TargetRotation, DeltaTime, 5.0f));
 79→	}
 80→
 81→	// 通过 Pawn 控制相机位置（如果有 Pawn）
 82→	if (APawn* ControlledPawn = GetPawn())
 83→	{
 84→		if (bSnapCameraNextFrame)
 85→		{
 86→			// 首帧直接跳到目标位置，避免切场景后相机大幅滑动
 87→			ControlledPawn->SetActorLocation(TargetLocation);
 88→			bSnapCameraNextFrame = false;
 89→		}
 90→		else
 91→		{
 92→			FVector CurrentLocation = ControlledPawn->GetActorLocation();
 93→			ControlledPawn->SetActorLocation(
 94→				FMath::VInterpTo(CurrentLocation, TargetLocation, DeltaTime, 5.0f)
 95→			);
 96→		}
 97→	}
 98→}
 99→
100→void ALFPWorldMapPlayerController::SetupInputComponent()
101→{
102→	Super::SetupInputComponent();
103→
104→	if (UEnhancedInputComponent* EnhancedInputComponent = Cast<UEnhancedInputComponent>(InputComponent))
105→	{
106→		// 基础操作
107→		EnhancedInputComponent->BindAction(ConfirmAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnConfirmAction);
108→		EnhancedInputComponent->BindAction(CancelAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnCancelAction);
109→
110→		// 相机操作
111→		EnhancedInputComponent->BindAction(CameraPanAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraPan);
112→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Started, this, &ALFPWorldMapPlayerController::OnCameraDragStarted);
113→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraDragTriggered);
114→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnCameraDragCompleted);
115→		EnhancedInputComponent->BindAction(CameraZoomAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraZoom);
116→
117→		// 编辑器切换
118→		EnhancedInputComponent->BindAction(ToggleEditorAction, ETriggerEvent::Started, this, &ALFPWorldMapPlayerController::OnToggleEditorAction);
119→	}
120→}
121→
122→// ============== 输入处理 ==============
123→
124→void ALFPWorldMapPlayerController::OnConfirmAction(const FInputActionValue& Value)
125→{
126→	bIsDragging = false;
127→	if (DragTime > DragThresholdTime)
128→	{
129→		DragTime = 0.f;
130→		return;
131→	}
132→	DragTime = 0.f;
133→
134→	// 编辑器模式优先处理
135→	if (WorldMapEditorComponent && WorldMapEditorComponent->IsEditorActive())
136→	{
137→		// 射线检测点击的节点
138→		FHitResult HitResult;
139→		GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
140→		ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
141→
142→		ELFPWorldMapEditorTool CurrentTool = WorldMapEditorComponent->GetCurrentTool();
143→
144→		switch (CurrentTool)
145→		{
146→		case ELFPWorldMapEditorTool::WMET_PlaceNode:
147→			{
148→				// 射线投射到 Z=0 平面获取世界坐标
149→				FVector WorldOrigin, WorldDirection;
150→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
151→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
152→				{
153→					float T = -WorldOrigin.Z / WorldDirection.Z;
154→					FVector HitPoint = WorldOrigin + WorldDirection * T;
155→					WorldMapEditorComponent->PlaceNodeAt(FVector2D(HitPoint.X, HitPoint.Y));
156→				}
157→			}
158→			break;
159→
160→		case ELFPWorldMapEditorTool::WMET_RemoveNode:
161→			if (ClickedNode)
162→			{
163→				WorldMapEditorComponent->SelectNode(ClickedNode);
164→				WorldMapEditorComponent->RemoveSelectedNode();
165→			}
166→			break;
167→
168→		case ELFPWorldMapEditorTool::WMET_MoveNode:
169→			if (ClickedNode)
170→			{
171→				WorldMapEditorComponent->SelectNode(ClickedNode);
172→			}
173→			else if (WorldMapEditorComponent->GetSelectedNode())
174→			{
175→				// 移动到点击位置
176→				FVector WorldOrigin, WorldDirection;
177→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
178→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
179→				{
180→					float T = -WorldOrigin.Z / WorldDirection.Z;
181→					FVector HitPoint = WorldOrigin + WorldDirection * T;
182→					WorldMapEditorComponent->MoveSelectedNodeTo(FVector2D(HitPoint.X, HitPoint.Y));
183→				}
184→			}
185→			break;
186→
187→		case ELFPWorldMapEditorTool::WMET_ConnectEdge:
188→			if (ClickedNode)
189→			{
190→				WorldMapEditorComponent->HandleEdgeConnection(ClickedNode);
191→			}
192→			break;
193→
194→		case ELFPWorldMapEditorTool::WMET_RemoveEdge:
195→			if (ClickedNode)
196→			{
197→				WorldMapEditorComponent->HandleEdgeRemoval(ClickedNode);
198→			}
199→			break;
200→
201→		case ELFPWorldMapEditorTool::WMET_SetNodeParams:
202→			if (ClickedNode)
203→			{
204→				WorldMapEditorComponent->SelectNode(ClickedNode);
205→				WorldMapEditorComponent->ApplyParamsToSelectedNode();
206→			}
207→			break;
208→
209→		default:
210→			break;
211→		}
212→		return;
213→	}
214→
215→	// 游戏模式：棋子移动中屏蔽点击
216→	ALFPWorldMapManager* Manager = GetWorldMapManager();
217→	if (Manager && Manager->IsPawnMoving()) return;
218→
219→	// 游戏模式：点击节点移动或进入
220→	FHitResult HitResult;
221→	GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
222→	ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
223→
224→	if (ClickedNode)
225→	{
226→		if (!Manager || !Manager->GetPlayerState()) return;
227→
228→		int32 CurrentNodeID = Manager->GetPlayerState()->CurrentNodeID;
229→
230→		// 点击当前节点 → 进入节点
231→		if (ClickedNode->NodeID == CurrentNodeID)
232→		{
233→			EnterNode(ClickedNode);
234→			return;
235→		}
236→
237→		// 点击相邻可达节点 → 移动
238→		TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
239→		if (ReachableIDs.Contains(ClickedNode->NodeID))
240→		{
241→			MoveToNode(ClickedNode);
242→		}
243→		else
244→		{
245→			// 不可达，只选中
246→			SelectNode(ClickedNode);
247→		}
248→	}
249→}
250→
251→void ALFPWorldMapPlayerController::OnCancelAction(const FInputActionValue& Value)
252→{
253→	// 取消选中和可达高亮
254→	ClearReachableHighlight();
255→	if (SelectedNode)
256→	{
257→		SelectedNode->SetHighlighted(false);
258→		SelectedNode = nullptr;
259→	}
260→}
261→
262→void ALFPWorldMapPlayerController::OnToggleEditorAction(const FInputActionValue& Value)
263→{
264→	if (!WorldMapEditorComponent) return;
265→
266→	WorldMapEditorComponent->ToggleEditorMode();
267→
268→	if (WorldMapEditorComponent->IsEditorActive())
269→	{
270→		// 创建或显示编辑器 Widget
271→		if (!WorldMapEditorWidget && WorldMapEditorWidgetClass)
272→		{
273→			WorldMapEditorWidget = CreateWidget<ULFPWorldMapEditorWidget>(this, WorldMapEditorWidgetClass);
274→			if (WorldMapEditorWidget)
275→			{
276→				WorldMapEditorWidget->AddToViewport();
277→				WorldMapEditorWidget->InitializeEditor(WorldMapEditorComponent);
278→			}
279→		}
280→		else if (WorldMapEditorWidget)
281→		{
282→			WorldMapEditorWidget->SetVisibility(ESlateVisibility::Visible);
283→		}
284→
285→		bShowMouseCursor = true;
286→	}
287→	else
288→	{
289→		// 隐藏编辑器 Widget
290→		if (WorldMapEditorWidget)
291→		{
292→			WorldMapEditorWidget->SetVisibility(ESlateVisibility::Collapsed);
293→		}
294→	}
295→}
296→
297→// ============== 相机操作 ==============
298→
299→void ALFPWorldMapPlayerController::OnCameraPan(const FInputActionValue& Value)
300→{
301→	FVector2D PanInput = Value.Get<FVector2D>();
302→	CameraOffset += FVector(PanInput.X, PanInput.Y, 0) * CameraPanSpeed * GetWorld()->GetDeltaSeconds();
303→}
304→
305→void ALFPWorldMapPlayerController::OnCameraDragStarted(const FInputActionValue& Value)
306→{
307→	bIsDragging = true;
308→	DragTime = 0.f;
309→	GetMousePosition(DragStartPosition.X, DragStartPosition.Y);
310→}
311→
312→void ALFPWorldMapPlayerController::OnCameraDragTriggered(const FInputActionValue& Value)
313→{
314→	if (!bIsDragging) return;
315→
316→	FVector2D CurrentMousePos;
317→	GetMousePosition(CurrentMousePos.X, CurrentMousePos.Y);
318→	FVector2D Delta = CurrentMousePos - DragStartPosition;
319→
320→	CameraOffset -= FVector(-Delta.Y, Delta.X, 0) * CameraDragSpeed;
321→	DragStartPosition = CurrentMousePos;
322→}
323→
324→void ALFPWorldMapPlayerController::OnCameraDragCompleted(const FInputActionValue& Value)
325→{
326→	bIsDragging = false;
327→}
328→
329→void ALFPWorldMapPlayerController::OnCameraZoom(const FInputActionValue& Value)
330→{
331→	float ZoomDelta = Value.Get<float>();
332→	CurrentZoom = FMath::Clamp(CurrentZoom - ZoomDelta * CameraZoomSpeed, MinZoomDistance, MaxZoomDistance);
333→
334→	// 应用缩放到相机
335→	if (APlayerCameraManager* CameraManager = PlayerCameraManager)
336→	{
337→		FVector CameraLocation = CameraManager->GetCameraLocation();
338→		CameraLocation.Z = CurrentZoom;
339→		CameraManager->SetManualCameraFade(0.f, FLinearColor::Black, false);
340→	}
341→}
342→
343→// ============== 节点交互 ==============
344→
345→void ALFPWorldMapPlayerController::SelectNode(ALFPWorldMapNode* Node)
346→{
347→	// 取消之前的选中
348→	if (SelectedNode)
349→	{
350→		SelectedNode->SetHighlighted(false);
351→	}
352→
353→	SelectedNode = Node;
354→
355→	if (SelectedNode)
356→	{
357→		SelectedNode->SetHighlighted(true);
358→	}
359→}
360→
361→void ALFPWorldMapPlayerController::MoveToNode(ALFPWorldMapNode* Node)
362→{
363→	if (!Node) return;
364→
365→	ALFPWorldMapManager* Manager = GetWorldMapManager();
