194→void ULFPWorldMapEditorComponent::HandleEdgeRemoval(ALFPWorldMapNode* Node)
195→{
196→	if (!Node) return;
197→
198→	ALFPWorldMapManager* Manager = GetWorldMapManager();
199→	if (!Manager) return;
200→
201→	if (!EdgeRemovalStartNode)
202→	{
203→		// 第一次点击：记录起点
204→		EdgeRemovalStartNode = Node;
205→		EdgeRemovalStartNode->SetHighlighted(true);
206→		UE_LOG(LogTemp, Log, TEXT("选择要删除的边起点: 节点 %d"), EdgeRemovalStartNode->NodeID);
207→	}
208→	else
209→	{
210→		// 第二次点击：删除边
211→		if (EdgeRemovalStartNode != Node)
212→		{
213→			bool bRemoved = Manager->RemoveEdge(EdgeRemovalStartNode->NodeID, Node->NodeID);
214→			if (bRemoved)
215→			{
216→				UE_LOG(LogTemp, Log, TEXT("删除边: %d <-> %d"), EdgeRemovalStartNode->NodeID, Node->NodeID);
217→			}
218→			else
219→			{
220→				UE_LOG(LogTemp, Warning, TEXT("边不存在: %d <-> %d"), EdgeRemovalStartNode->NodeID, Node->NodeID);
221→			}
222→		}
223→
224→		// 清除高亮和状态
225→		EdgeRemovalStartNode->SetHighlighted(false);
226→		EdgeRemovalStartNode = nullptr;
