419→void ALFPWorldMapPlayerController::EnterNode(ALFPWorldMapNode* Node)
420→{
421→	if (!Node) return;
422→
423→	UE_LOG(LogTemp, Log, TEXT("进入节点 %d，类型: %d"), Node->NodeID, (int32)Node->NodeType);
424→
425→	switch (Node->NodeType)
426→	{
427→	case ELFPWorldNodeType::WNT_Battle:
428→	case ELFPWorldNodeType::WNT_Boss:
429→		EnterBattle(Node);
430→		break;
431→
432→	case ELFPWorldNodeType::WNT_Event:
433→		// TODO: 触发事件系统
434→		UE_LOG(LogTemp, Log, TEXT("事件节点 %d: EventID=%s"), Node->NodeID, *Node->EventID);
435→		break;
436→
437→	case ELFPWorldNodeType::WNT_Shop:
438→		// TODO: 打开商店 UI
439→		UE_LOG(LogTemp, Log, TEXT("商店节点 %d"), Node->NodeID);
440→		break;
441→
442→	case ELFPWorldNodeType::WNT_Town:
443→		// TODO: 进入城镇
444→		UE_LOG(LogTemp, Log, TEXT("城镇节点 %d"), Node->NodeID);
445→		break;
446→
447→	case ELFPWorldNodeType::WNT_QuestNPC:
448→		// TODO: 触发任务对话
449→		UE_LOG(LogTemp, Log, TEXT("任务NPC节点 %d"), Node->NodeID);
450→		break;
451→
452→	case ELFPWorldNodeType::WNT_SkillNode:
453→		// TODO: 打开技能树 UI
454→		UE_LOG(LogTemp, Log, TEXT("技能节点 %d"), Node->NodeID);
455→		break;
456→
457→	default:
458→		break;
459→	}
