 23→// ============== 节点管理 ==============
 24→
 25→ALFPWorldMapNode* ALFPWorldMapManager::SpawnNode(int32 NodeID, FVector2D Position, ELFPWorldNodeType NodeType)
 26→{
 27→	// 检查 ID 冲突
 28→	if (NodeMap.Contains(NodeID))
 29→	{
 30→		UE_LOG(LogTemp, Warning, TEXT("SpawnNode: 节点 ID %d 已存在"), NodeID);
 31→		return NodeMap[NodeID];
 32→	}
 33→
 34→	if (!NodeActorClass)
 35→	{
 36→		UE_LOG(LogTemp, Error, TEXT("SpawnNode: NodeActorClass 未配置"));
 37→		return nullptr;
 38→	}
 39→
 40→	FVector SpawnLocation(Position.X, Position.Y, 0.f);
 41→	FActorSpawnParameters SpawnParams;
 42→	SpawnParams.Owner = this;
 43→
 44→	ALFPWorldMapNode* NewNode = GetWorld()->SpawnActor<ALFPWorldMapNode>(
 45→		NodeActorClass, SpawnLocation, FRotator::ZeroRotator, SpawnParams);
 46→
 47→	if (!NewNode) return nullptr;
 48→
 49→	NewNode->NodeID = NodeID;
 50→	NewNode->NodeType = NodeType;
 51→	NewNode->AttachToActor(this, FAttachmentTransformRules::KeepWorldTransform);
 52→
 53→	// 应用视觉数据
 54→	if (ULFPWorldNodeDataAsset* VisualData = GetNodeVisualForType(NodeType))
 55→	{
 56→		NewNode->SetNodeVisualData(VisualData);
 57→	}
 58→
 59→	NodeMap.Add(NodeID, NewNode);
 60→
 61→	// 确保邻接表有条目
 62→	if (!AdjacencyList.Contains(NodeID))
 63→	{
 64→		AdjacencyList.Add(NodeID, TSet<int32>());
 65→	}
 66→
 67→	// 更新 ID 计数器
 68→	if (NodeID >= NextNodeID)
 69→	{
 70→		NextNodeID = NodeID + 1;
 71→	}
 72→
 73→	return NewNode;
 74→}
