139→// ============== 边管理 ==============
140→
141→ALFPWorldMapEdge* ALFPWorldMapManager::AddEdge(int32 FromID, int32 ToID, int32 TurnCost)
142→{
143→	// 验证节点存在
144→	if (!NodeMap.Contains(FromID) || !NodeMap.Contains(ToID))
145→	{
146→		UE_LOG(LogTemp, Warning, TEXT("AddEdge: 节点 %d 或 %d 不存在"), FromID, ToID);
147→		return nullptr;
148→	}
149→
150→	// 不能自连
151→	if (FromID == ToID)
152→	{
153→		UE_LOG(LogTemp, Warning, TEXT("AddEdge: 不能自连节点 %d"), FromID);
154→		return nullptr;
155→	}
156→
157→	FIntPoint Key = MakeEdgeKey(FromID, ToID);
158→
159→	// 检查重复
160→	if (EdgeMap.Contains(Key))
161→	{
162→		UE_LOG(LogTemp, Warning, TEXT("AddEdge: 边 %d-%d 已存在"), FromID, ToID);
163→		return EdgeMap[Key];
164→	}
165→
166→	if (!EdgeActorClass)
167→	{
168→		UE_LOG(LogTemp, Error, TEXT("AddEdge: EdgeActorClass 未配置"));
169→		return nullptr;
170→	}
171→
172→	FActorSpawnParameters SpawnParams;
173→	SpawnParams.Owner = this;
174→
175→	ALFPWorldMapEdge* NewEdge = GetWorld()->SpawnActor<ALFPWorldMapEdge>(
176→		EdgeActorClass, FVector::ZeroVector, FRotator::ZeroRotator, SpawnParams);
177→
178→	if (!NewEdge) return nullptr;
179→
180→	NewEdge->FromNodeID = FromID;
181→	NewEdge->ToNodeID = ToID;
182→	NewEdge->TravelTurnCost = TurnCost;
183→	NewEdge->AttachToActor(this, FAttachmentTransformRules::KeepWorldTransform);
184→
185→	// 设置边精灵
186→	if (EdgeSprite)
187→	{
188→		NewEdge->SetEdgeSprite(EdgeSprite);
189→	}
190→
191→	// 更新视觉位置
192→	ALFPWorldMapNode* FromNode = NodeMap[FromID];
193→	ALFPWorldMapNode* ToNode = NodeMap[ToID];
194→	NewEdge->UpdateVisualPosition(FromNode->GetActorLocation(), ToNode->GetActorLocation());
195→
196→	// 存储
197→	EdgeMap.Add(Key, NewEdge);
198→
199→	// 更新邻接表（双向）
200→	AdjacencyList.FindOrAdd(FromID).Add(ToID);
201→	AdjacencyList.FindOrAdd(ToID).Add(FromID);
202→
203→	// 更新节点-边索引
204→	NodeEdgeIndex.FindOrAdd(FromID).Add(Key);
205→	NodeEdgeIndex.FindOrAdd(ToID).Add(Key);
206→
207→	return NewEdge;
208→}
209→
210→bool ALFPWorldMapManager::RemoveEdge(int32 FromID, int32 ToID)
211→{
212→	FIntPoint Key = MakeEdgeKey(FromID, ToID);
213→
214→	ALFPWorldMapEdge** Found = EdgeMap.Find(Key);
215→	if (!Found) return false;
216→
217→	// 销毁 Actor
218→	if (*Found)
219→	{
220→		(*Found)->Destroy();
221→	}
222→
223→	EdgeMap.Remove(Key);
224→
225→	// 更新邻接表
226→	if (TSet<int32>* FromNeighbors = AdjacencyList.Find(FromID))
227→	{
228→		FromNeighbors->Remove(ToID);
229→	}
230→	if (TSet<int32>* ToNeighbors = AdjacencyList.Find(ToID))
231→	{
232→		ToNeighbors->Remove(FromID);
233→	}
234→
235→	// 更新节点-边索引
236→	if (TArray<FIntPoint>* FromEdges = NodeEdgeIndex.Find(FromID))
237→	{
238→		FromEdges->Remove(Key);
239→	}
240→	if (TArray<FIntPoint>* ToEdges = NodeEdgeIndex.Find(ToID))
241→	{
242→		ToEdges->Remove(Key);
243→	}
244→
245→	return true;
246→}
