248→ALFPWorldMapEdge* ALFPWorldMapManager::GetEdge(int32 FromID, int32 ToID) const
249→{
250→	FIntPoint Key = MakeEdgeKey(FromID, ToID);
251→	if (const auto* Found = EdgeMap.Find(Key))
252→	{
253→		return *Found;
254→	}
