  43→void ALFPTacticsPlayerController::BeginPlay()
  44→{
  45→    Super::BeginPlay();
  46→
  47→    // 设置输入模式
  48→    FInputModeGameAndUI InputMode;
  49→    InputMode.SetLockMouseToViewportBehavior(EMouseLockMode::DoNotLock);
  50→    InputMode.SetHideCursorDuringCapture(false);
  51→    SetInputMode(InputMode);
  52→    bShowMouseCursor = true;
  53→
  54→    // 获取网格管理器
  55→    TArray<AActor*> FoundActors;
  56→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPHexGridManager::StaticClass(), FoundActors);
  57→    if (FoundActors.Num() > 0)
  58→    {
  59→        GridManager = Cast<ALFPHexGridManager>(FoundActors[0]);
  60→    }
  61→
  62→    // 设置Enhanced Input
  63→    if (UEnhancedInputLocalPlayerSubsystem* Subsystem = ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer()))
  64→    {
  65→        if (DefaultInputMapping)
  66→        {
  67→            Subsystem->AddMappingContext(DefaultInputMapping, 0);
  68→        }
  69→    }
  70→
  71→    // 初始化UI
  72→    if (TurnSpeedWidgetClass)
  73→    {
  74→        TurnSpeedListWidget = CreateWidget<ULFPTurnSpeedListWidget>(this, TurnSpeedWidgetClass);
  75→        if (TurnSpeedListWidget)
  76→        {
  77→            TurnSpeedListWidget->AddToViewport();
  78→            TurnSpeedListWidget->InitializeTurnOrder(); // 初始化单位顺序
  79→        }
  80→    }
  81→
  82→    // 绑定阶段变化委托
  83→    if (ALFPTurnManager* TurnManager = GetTurnManager())
  84→    {
  85→        TurnManager->OnPhaseChanged.AddDynamic(this, &ALFPTacticsPlayerController::OnPhaseChanged);
  86→
  87→        // StartGame() 在 GameMode::StartPlay() 中执行，早于 PlayerController::BeginPlay()
  88→        // 此时阶段已设置但未广播，需主动检查并触发布置阶段
  89→        if (TurnManager->GetCurrentPhase() == EBattlePhase::BP_Deployment)
  90→        {
  91→            OnDeploymentPhaseStarted();
  92→        }
  93→    }
  94→
  95→    // 场景切换淡入效果
  96→    if (PlayerCameraManager)
  97→    {
  98→        ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
  99→        float FadeDuration = GI ? GI->TransitionFadeDuration : 0.5f;
 100→        PlayerCameraManager->StartCameraFade(1.f, 0.f, FadeDuration, FLinearColor::Black, false, false);
 101→    }
 102→
 103→    // 首帧跳过相机平滑插值
 104→    bSnapCameraNextFrame = true;
 105→}
