 738→bool ALFPTacticsPlayerController::AttackTarget(ALFPTacticsUnit* Attacker, ALFPTacticsUnit* Target)
 739→{
 740→    if (!Attacker || !Target || !Attacker->CanAct())
 741→    {
 742→        return false;
 743→    }
 744→
 745→    // 计算攻击代价
 746→    const int32 AttackCost = 1;
 747→
 748→    bIsAttacking = false;
 749→    CurrentControlState = EPlayControlState::MoveState;
 750→
 751→    if (!Attacker->HasEnoughActionPoints(AttackCost))
 752→    {
 753→        return false;
 754→    }
 755→
 756→    // 执行攻击逻辑
 757→    bool bAttackSucceed = Attacker->AttackTarget(Target);
 758→
 759→    if (bAttackSucceed)
 760→    {
 761→		// 消耗行动力
 762→		Attacker->ConsumeActionPoints(AttackCost);
 763→        ShowUnitRange(EUnitRange::UR_Default);
 764→    }
 765→    else
 766→    {
 767→        ShowUnitRange(EUnitRange::UR_Move);
 768→    }
 769→
 770→    // 通知回合管理器单位完成行动
 771→    if (!Attacker->HasEnoughActionPoints(1))
 772→    {
 773→		if (bAttackSucceed)
 774→		{
 775→            SkipTurn(Attacker);
 776→		}
 777→    }
 778→
 779→    return bAttackSucceed;
 780→}
