1137→void ALFPTacticsPlayerController::PickupDeployedUnit(ALFPTacticsUnit* Unit)
1138→{
1139→    if (!Unit) return;
1140→
1141→    // 找到对应的 PartyIndex
1142→    int32 FoundIndex = DeployedUnits.Find(Unit);
1143→    if (FoundIndex == INDEX_NONE) return;
1144→
1145→    // 清除格子占用
1146→    ALFPHexTile* OldTile = Unit->GetCurrentTile();
1147→    if (OldTile)
1148→    {
1149→        OldTile->SetIsOccupied(false);
1150→        OldTile->SetUnitOnTile(nullptr);
1151→    }
1152→
1153→    // 设置为跟随鼠标的预览
1154→    PlacingUnitPreview = Unit;
1155→    PlacingPartyIndex = FoundIndex;
1156→    bIsPlacingUnit = true;
1157→
1158→    // 清除已布置记录
1159→    DeployedUnits[FoundIndex] = nullptr;
1160→
1161→    // 更新 UI
1162→    if (DeploymentWidget)
1163→    {
1164→        DeploymentWidget->MarkUnitPlaced(FoundIndex, false);
1165→    }
1166→
1167→    UE_LOG(LogTemp, Log, TEXT("拾起已放置的单位（索引 %d）"), FoundIndex);
1168→}
