251→bool ALFPHexGridManager::SaveMapToCSV(const FString& CSVFilePath)
252→{
253→	// CSV 头部（UE DataTable 格式：第一列为 RowName）
254→	FString CSVContent = TEXT("---,Q,R,TerrainType,DecorationID,SpawnFaction,SpawnIndex,EventTag\n");
255→
256→	for (const auto& Pair : GridMap)
257→	{
258→		ALFPHexTile* Tile = Pair.Value;
259→		if (!Tile) continue;
260→
261→		FLFPHexCoordinates Coord = Tile->GetCoordinates();
262→		FString RowName = FString::Printf(TEXT("%d_%d"), Coord.Q, Coord.R);
263→
264→		// 地形类型枚举名
265→		ELFPTerrainType TType = Tile->GetTerrainData() ? Tile->GetTerrainData()->TerrainType : ELFPTerrainType::TT_Grass;
266→		FString TerrainStr = UEnum::GetValueAsString(TType);
267→		TerrainStr = TerrainStr.RightChop(TerrainStr.Find(TEXT("::")) + 2);
268→
269→		// 装饰 ID
270→		FString DecoStr = Tile->DecorationID.IsNone() ? TEXT("") : Tile->DecorationID.ToString();
271→
272→		// 出生点阵营
273→		FString SpawnStr = UEnum::GetValueAsString(Tile->SpawnFaction);
274→		SpawnStr = SpawnStr.RightChop(SpawnStr.Find(TEXT("::")) + 2);
275→
276→		// 事件标签
277→		FString EventStr = Tile->EventTag.IsValid() ? Tile->EventTag.ToString() : TEXT("");
278→
279→		CSVContent += FString::Printf(TEXT("%s,%d,%d,%s,%s,%s,%d,%s\n"),
280→			*RowName, Coord.Q, Coord.R, *TerrainStr, *DecoStr,
281→			*SpawnStr, Tile->SpawnIndex, *EventStr);
282→	}
283→
284→	// 确保目录存在
285→	FString Directory = FPaths::GetPath(CSVFilePath);
286→	if (!FPaths::DirectoryExists(Directory))
287→	{
288→		IFileManager::Get().MakeDirectory(*Directory, true);
289→	}
290→
291→	bool bSuccess = FFileHelper::SaveStringToFile(CSVContent, *CSVFilePath,
292→		FFileHelper::EEncodingOptions::ForceUTF8WithoutBOM);
293→
294→	if (bSuccess)
295→	{
296→		UE_LOG(LogTemp, Log, TEXT("SaveMapToCSV: 保存 %d 个格子到 %s"), GridMap.Num(), *CSVFilePath);
297→	}
298→	else
299→	{
300→		UE_LOG(LogTemp, Error, TEXT("SaveMapToCSV: 保存失败 %s"), *CSVFilePath);
301→	}
302→	return bSuccess;
303→}
