266→void ULFPWorldMapEditorComponent::EnterBattleMapEditor()
267→{
268→	if (!SelectedNode)
269→	{
270→		UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 未选中节点"));
271→		return;
272→	}
273→
274→	if (SelectedNode->NodeType != ELFPWorldNodeType::WNT_Battle)
275→	{
276→		UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 选中的不是战斗节点"));
277→		return;
278→	}
279→
280→	if (SelectedNode->BattleMapName.IsEmpty())
281→	{
282→		UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 战斗地图名称为空"));
283→		return;
284→	}
285→
286→	// 获取战斗地图编辑器组件（在同一个 PlayerController 上）
287→	ULFPMapEditorComponent* BattleEditor = GetOwner()->FindComponentByClass<ULFPMapEditorComponent>();
288→	if (!BattleEditor)
289→	{
290→		UE_LOG(LogTemp, Error, TEXT("EnterBattleMapEditor: 找不到战斗地图编辑器组件"));
291→		return;
292→	}
293→
294→	// 加载战斗地图
295→	bool bLoaded = BattleEditor->LoadMap(SelectedNode->BattleMapName);
296→	if (!bLoaded)
297→	{
298→		UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 加载战斗地图失败，创建新地图"));
299→		BattleEditor->NewMap(10, 10);
300→	}
301→
302→	// 激活战斗地图编辑器
303→	if (!BattleEditor->IsEditorActive())
304→	{
305→		BattleEditor->ToggleEditorMode();
306→	}
307→
308→	bIsEditingBattleMap = true;
309→	UE_LOG(LogTemp, Log, TEXT("进入战斗地图编辑: %s"), *SelectedNode->BattleMapName);
310→}
