462→void ALFPWorldMapPlayerController::EnterBattle(ALFPWorldMapNode* BattleNode)
463→{
464→	if (!BattleNode) return;
465→
466→	ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
467→	if (!GI) return;
468→
469→	ALFPWorldMapManager* Manager = GetWorldMapManager();
470→	if (!Manager) return;
471→
472→	// 保存世界地图快照
473→	FLFPWorldMapSnapshot Snapshot;
474→	Snapshot.WorldMapName = Manager->GetCurrentWorldMapName();
475→	if (ULFPWorldMapPlayerState* PS = Manager->GetPlayerState())
476→	{
477→		Snapshot.CurrentNodeID = PS->CurrentNodeID;
478→		Snapshot.CurrentTurn = PS->CurrentTurn;
479→		Snapshot.VisitedNodeIDs = PS->VisitedNodeIDs;
480→		Snapshot.RevealedNodeIDs = PS->RevealedNodeIDs;
481→	}
482→
483→	// 收集已触发节点
484→	for (const auto& Pair : Manager->GetNodeMap())
485→	{
486→		if (Pair.Value && Pair.Value->bHasBeenTriggered)
487→		{
488→			Snapshot.TriggeredNodeIDs.Add(Pair.Key);
489→		}
490→	}
491→
492→	GI->SaveWorldMapSnapshot(Snapshot);
493→
494→	// 设置战斗请求
495→	FLFPBattleRequest Request;
496→	Request.SourceNodeID = BattleNode->NodeID;
497→	Request.BattleMapName = BattleNode->BattleMapName;
498→	Request.StarRating = BattleNode->StarRating;
499→	Request.bCanEscape = BattleNode->bCanEscape;
500→	Request.BaseGoldReward = BattleNode->BaseGoldReward;
501→	Request.BaseFoodReward = BattleNode->BaseFoodReward;
502→	GI->SetBattleRequest(Request);
503→
504→	// 切换到战斗关卡
505→	GI->TransitionToBattle(TEXT(""));
506→}
