 57→void ULFPMapEditorComponent::ApplyToolToTile(ALFPHexTile* Tile)
 58→{
 59→	if (!Tile || !bEditorActive) return;
 60→
 61→	ALFPHexGridManager* GM = GetGridManager();
 62→	if (!GM) return;
 63→
 64→	switch (CurrentTool)
 65→	{
 66→	case ELFPMapEditorTool::MET_Terrain:
 67→		if (ULFPTerrainDataAsset* TerrainDA = GM->GetTerrainDataForType(BrushTerrainType))
 68→		{
 69→			Tile->SetTerrainData(TerrainDA);
 70→			// 更新该格子及邻居的地形过渡
 71→			FLFPHexCoordinates Coord = Tile->GetCoordinates();
 72→			GM->UpdateTransitionsAround(Coord.Q, Coord.R);
 73→		}
 74→		break;
 75→
 76→	case ELFPMapEditorTool::MET_Decoration:
 77→		Tile->SetDecorationByID(BrushDecorationID, GM->GetDecorationSprite(BrushDecorationID));
 78→		break;
 79→
 80→	case ELFPMapEditorTool::MET_SpawnPoint:
 81→		Tile->SpawnFaction = BrushSpawnFaction;
 82→		Tile->SpawnIndex = BrushSpawnIndex;
 83→		break;
 84→
 85→	case ELFPMapEditorTool::MET_Event:
 86→		Tile->EventTag = BrushEventTag;
 87→		break;
 88→
 89→	case ELFPMapEditorTool::MET_RemoveTile:
 90→		{
 91→			FLFPHexCoordinates Coord = Tile->GetCoordinates();
 92→			int32 RemovedQ = Coord.Q;
 93→			int32 RemovedR = Coord.R;
 94→			GM->RemoveTile(RemovedQ, RemovedR);
 95→			// 更新被移除格子周围邻居的过渡
 96→			GM->UpdateTransitionsAround(RemovedQ, RemovedR);
 97→		}
 98→		break;
 99→
100→	default:
101→		break;
102→	}
103→}
