105→void ULFPMapEditorComponent::ApplyToolToCoord(int32 Q, int32 R)
106→{
107→	if (!bEditorActive) return;
108→
109→	ALFPHexGridManager* GM = GetGridManager();
110→	if (!GM) return;
111→
112→	if (CurrentTool == ELFPMapEditorTool::MET_AddTile)
113→	{
114→		GM->AddTile(Q, R);
115→		// 更新新格子及邻居的地形过渡
116→		GM->UpdateTransitionsAround(Q, R);
117→	}
118→}
