		RefreshUnitIcons();
	}
}

void ULFPUnitMergeWidget::ClearSlots()
{
	SlotA = FLFPMergeSlotInfo();
	SlotB = FLFPMergeSlotInfo();
	UpdateSlotVisual(SlotA, Image_SlotA);
	UpdateSlotVisual(SlotB, Image_SlotB);
	UpdatePreview();
}

void ULFPUnitMergeWidget::UpdatePreview()
{
	bool bCanMerge = false;

	if (!SlotA.bIsEmpty && !SlotB.bIsEmpty)
	{
		// 检查匹配：同种同阶且未满阶
		if (SlotA.Unit.TypeID == SlotB.Unit.TypeID
			&& SlotA.Unit.Tier == SlotB.Unit.Tier
			&& SlotA.Unit.Tier < (CachedGameInstance ? CachedGameInstance->MaxUnitTier : 3))
		{
			bCanMerge = true;

			// 显示预览
			int32 NewTier = SlotA.Unit.Tier + 1;

			if (Image_PreviewIcon && CachedRegistry)
			{
				FLFPUnitRegistryEntry RegEntry;
				if (CachedRegistry->FindEntry(SlotA.Unit.TypeID, RegEntry) && RegEntry.Icon)
				{
					Image_PreviewIcon->SetBrushFromTexture(RegEntry.Icon);
					Image_PreviewIcon->SetRenderOpacity(1.f);
				}
			}

			if (Text_PreviewName && CachedRegistry)
			{
				FLFPUnitRegistryEntry RegEntry;
				if (CachedRegistry->FindEntry(SlotA.Unit.TypeID, RegEntry))
				{
					FString PreviewText = FString::Printf(TEXT("%s %s"),
						*RegEntry.DisplayName.ToString(), *MakeTierStars(NewTier));
					Text_PreviewName->SetText(FText::FromString(PreviewText));
				}
			}
		}
		else
		{
			// 不匹配
			if (Text_PreviewName)
			{
				Text_PreviewName->SetText(FText::FromString(TEXT("无法合并")));
			}
			if (Image_PreviewIcon)
			{
				Image_PreviewIcon->SetRenderOpacity(0.2f);
			}
		}
	}
	else
	{
		// 合成框未满
		if (Text_PreviewName)
		{
			Text_PreviewName->SetText(FText::FromString(TEXT("请选择两个同种同阶单位")));
		}
		if (Image_PreviewIcon)
		{
			Image_PreviewIcon->SetRenderOpacity(0.2f);
		}
	}

	if (Button_Merge)
	{
		Button_Merge->SetIsEnabled(bCanMerge);
	}
}

void ULFPUnitMergeWidget::OnMergeClicked()
{
	if (!CachedGameInstance || SlotA.bIsEmpty || SlotB.bIsEmpty) return;

	bool bSuccess = CachedGameInstance->MergeUnits(
		SlotA.bIsParty, SlotA.SlotIndex,
		SlotB.bIsParty, SlotB.SlotIndex);

	if (bSuccess)
	{
		UE_LOG(LogTemp, Log, TEXT("升阶 Widget: 合并成功"));
	}

	ClearSlots();
	RefreshUnitIcons();
}

void ULFPUnitMergeWidget::OnClearClicked()
{
	ClearSlots();
	RefreshUnitIcons();
}

void ULFPUnitMergeWidget::OnCloseClicked()
{
	OnClosed.Broadcast();
	RemoveFromParent();
}

void ULFPUnitMergeWidget::UpdateSlotVisual(const FLFPMergeSlotInfo& Slot, UImage* SlotImage)
{
	if (!SlotImage) return;

	if (Slot.bIsEmpty)
	{
		SlotImage->SetRenderOpacity(0.2f);
		SlotImage->SetBrushFromTexture(nullptr);
	}
	else if (CachedRegistry)
	{
		FLFPUnitRegistryEntry RegEntry;
		if (CachedRegistry->FindEntry(Slot.Unit.TypeID, RegEntry) && RegEntry.Icon)
		{
			SlotImage->SetBrushFromTexture(RegEntry.Icon);
			SlotImage->SetRenderOpacity(1.f);
		}
	}
}

FString ULFPUnitMergeWidget::MakeTierStars(int32 Tier) const
{
	FString Stars;
	int32 MaxTier = CachedGameInstance ? CachedGameInstance->MaxUnitTier : 3;
	for (int32 i = 0; i < MaxTier; ++i)
	{
		Stars += (i < Tier) ? TEXT("★") : TEXT("☆");
	}
	return Stars;
}

