	if (Button_SlotA) Button_SlotA->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnSlotAClicked);
	if (Button_SlotB) Button_SlotB->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnSlotBClicked);
