 10→void ULFPUnitMergeWidget::NativeConstruct()
 11→{
 12→	Super::NativeConstruct();
 13→
 14→	if (Button_SlotA) Button_SlotA->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnSlotAClicked);
 15→	if (Button_SlotB) Button_SlotB->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnSlotBClicked);
 16→	if (Button_Merge) Button_Merge->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnMergeClicked);
 17→	if (Button_Clear) Button_Clear->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnClearClicked);
 18→	if (Button_Close) Button_Close->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnCloseClicked);
 19→
 20→	if (Button_Merge) Button_Merge->SetIsEnabled(false);
 21→}
 22→
 23→void ULFPUnitMergeWidget::Setup(ULFPGameInstance* GI, ULFPUnitRegistryDataAsset* Registry)
 24→{
 25→	CachedGameInstance = GI;
 26→	CachedRegistry = Registry;
 27→	ClearSlots();
 28→	RefreshUnitIcons();
 29→}
 30→
 31→// 创建单个单位 icon 按钮的辅助函数
 32→static UButton* CreateUnitIconButton(ULFPUnitMergeWidget* Outer, UHorizontalBox* Container,
 33→	ULFPUnitRegistryDataAsset* Registry, const FLFPUnitEntry& Unit, bool bDisabled)
 34→{
 35→	UButton* Btn = NewObject<UButton>(Outer);
 36→	if (!Btn || !Container) return nullptr;
 37→
 38→	UHorizontalBoxSlot* BoxSlot = Container->AddChildToHorizontalBox(Btn);
 39→	if (BoxSlot)
 40→	{
 41→		BoxSlot->SetPadding(FMargin(4.f));
 42→	}
 43→
 44→	// 设置图标样式
 45→	FLFPUnitRegistryEntry RegEntry;
 46→	if (Registry && Registry->FindEntry(Unit.TypeID, RegEntry) && RegEntry.Icon)
 47→	{
 48→		FButtonStyle Style = Btn->GetStyle();
 49→		Style.Normal.SetResourceObject(RegEntry.Icon);
 50→		Style.Normal.ImageSize = FVector2D(64.f, 64.f);
 51→		Style.Hovered.SetResourceObject(RegEntry.Icon);
 52→		Style.Hovered.ImageSize = FVector2D(64.f, 64.f);
 53→		Style.Pressed.SetResourceObject(RegEntry.Icon);
 54→		Style.Pressed.ImageSize = FVector2D(64.f, 64.f);
 55→		Btn->SetStyle(Style);
 56→	}
 57→
 58→	if (bDisabled)
 59→	{
 60→		Btn->SetIsEnabled(false);
 61→		Btn->SetRenderOpacity(0.4f);
 62→	}
 63→
 64→	return Btn;
 65→}
 66→
 67→void ULFPUnitMergeWidget::RefreshUnitIcons()
 68→{
 69→	UnitIconButtons.Empty();
 70→	ButtonToUnitMap.Empty();
 71→
 72→	if (!CachedGameInstance || !CachedRegistry) return;
 73→
 74→	if (Box_PartyUnits) Box_PartyUnits->ClearChildren();
 75→	if (Box_ReserveUnits) Box_ReserveUnits->ClearChildren();
 76→
 77→	// 队伍单位
 78→	for (int32 i = 0; i < CachedGameInstance->PartyUnits.Num(); ++i)
 79→	{
 80→		const FLFPUnitEntry& Unit = CachedGameInstance->PartyUnits[i];
 81→		if (!Unit.IsValid()) continue;
 82→
 83→		bool bInSlot = (!SlotA.bIsEmpty && SlotA.bIsParty && SlotA.SlotIndex == i)
 84→			|| (!SlotB.bIsEmpty && SlotB.bIsParty && SlotB.SlotIndex == i);
 85→
 86→		UButton* Btn = CreateUnitIconButton(this, Box_PartyUnits, CachedRegistry, Unit, bInSlot);
 87→		if (!Btn) continue;
 88→
 89→		UnitIconButtons.Add(Btn);
 90→		ButtonToUnitMap.Add(Btn, {true, i});
 91→
 92→		if (!bInSlot)
 93→		{
 94→			Btn->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnUnitIconClicked);
 95→		}
 96→	}
 97→
 98→	// 备战营单位
 99→	for (int32 i = 0; i < CachedGameInstance->ReserveUnits.Num(); ++i)
100→	{
101→		const FLFPUnitEntry& Unit = CachedGameInstance->ReserveUnits[i];
102→		if (!Unit.IsValid()) continue;
103→
104→		bool bInSlot = (!SlotA.bIsEmpty && !SlotA.bIsParty && SlotA.SlotIndex == i)
105→			|| (!SlotB.bIsEmpty && !SlotB.bIsParty && SlotB.SlotIndex == i);
106→
107→		UButton* Btn = CreateUnitIconButton(this, Box_ReserveUnits, CachedRegistry, Unit, bInSlot);
108→		if (!Btn) continue;
109→
110→		UnitIconButtons.Add(Btn);
111→		ButtonToUnitMap.Add(Btn, {false, i});
112→
113→		if (!bInSlot)
114→		{
115→			Btn->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnUnitIconClicked);
116→		}
117→	}
118→}
119→
120→void ULFPUnitMergeWidget::OnUnitIconClicked()
121→{
122→	// 找到触发点击的按钮
123→	for (const auto& Pair : ButtonToUnitMap)
124→	{
125→		UButton* Btn = Pair.Key;
126→		if (Btn && Btn->IsHovered())
127→		{
128→			PlaceUnitInSlot(Pair.Value.bIsParty, Pair.Value.SlotIndex);
129→			return;
130→		}
131→	}
132→}
133→
134→void ULFPUnitMergeWidget::PlaceUnitInSlot(bool bIsParty, int32 Index)
135→{
136→	if (!CachedGameInstance) return;
137→
138→	const TArray<FLFPUnitEntry>& SourceArray = bIsParty
139→		? CachedGameInstance->PartyUnits
140→		: CachedGameInstance->ReserveUnits;
141→
142→	if (!SourceArray.IsValidIndex(Index)) return;
143→
144→	FLFPMergeSlotInfo NewSlot;
145→	NewSlot.bIsParty = bIsParty;
146→	NewSlot.SlotIndex = Index;
147→	NewSlot.Unit = SourceArray[Index];
148→	NewSlot.bIsEmpty = false;
149→
150→	// 放入第一个空的合成框
151→	if (SlotA.bIsEmpty)
152→	{
153→		SlotA = NewSlot;
154→	}
155→	else if (SlotB.bIsEmpty)
156→	{
157→		SlotB = NewSlot;
158→	}
159→	else
160→	{
161→		// 两个都满了，不操作
162→		return;
163→	}
164→
165→	UpdateSlotVisual(SlotA, Image_SlotA);
166→	UpdateSlotVisual(SlotB, Image_SlotB);
167→	UpdatePreview();
168→	RefreshUnitIcons();
169→}
170→
171→void ULFPUnitMergeWidget::OnSlotAClicked()
172→{
173→	if (!SlotA.bIsEmpty)
174→	{
175→		SlotA = FLFPMergeSlotInfo();
176→		UpdateSlotVisual(SlotA, Image_SlotA);
177→		UpdatePreview();
178→		RefreshUnitIcons();
179→	}
180→}
181→
182→void ULFPUnitMergeWidget::OnSlotBClicked()
183→{
184→	if (!SlotB.bIsEmpty)
185→	{
186→		SlotB = FLFPMergeSlotInfo();
187→		UpdateSlotVisual(SlotB, Image_SlotB);
188→		UpdatePreview();
189→		RefreshUnitIcons();
190→	}
191→}
192→
193→void ULFPUnitMergeWidget::ClearSlots()
194→{
195→	SlotA = FLFPMergeSlotInfo();
196→	SlotB = FLFPMergeSlotInfo();
197→	UpdateSlotVisual(SlotA, Image_SlotA);
198→	UpdateSlotVisual(SlotB, Image_SlotB);
199→	UpdatePreview();
200→}
201→
202→void ULFPUnitMergeWidget::UpdatePreview()
203→{
204→	bool bCanMerge = false;
205→
206→	if (!SlotA.bIsEmpty && !SlotB.bIsEmpty)
207→	{
208→		// 检查匹配：同种同阶且未满阶
209→		if (SlotA.Unit.TypeID == SlotB.Unit.TypeID
210→			&& SlotA.Unit.Tier == SlotB.Unit.Tier
211→			&& SlotA.Unit.Tier < (CachedGameInstance ? CachedGameInstance->MaxUnitTier : 3))
212→		{
213→			bCanMerge = true;
214→
215→			// 显示预览
216→			int32 NewTier = SlotA.Unit.Tier + 1;
217→
218→			if (Image_PreviewIcon && CachedRegistry)
219→			{
220→				FLFPUnitRegistryEntry RegEntry;
221→				if (CachedRegistry->FindEntry(SlotA.Unit.TypeID, RegEntry) && RegEntry.Icon)
222→				{
223→					Image_PreviewIcon->SetBrushFromTexture(RegEntry.Icon);
224→					Image_PreviewIcon->SetRenderOpacity(1.f);
225→				}
226→			}
227→
228→			if (Text_PreviewName && CachedRegistry)
229→			{
230→				FLFPUnitRegistryEntry RegEntry;
231→				if (CachedRegistry->FindEntry(SlotA.Unit.TypeID, RegEntry))
232→				{
233→					FString PreviewText = FString::Printf(TEXT("%s %s"),
234→						*RegEntry.DisplayName.ToString(), *MakeTierStars(NewTier));
235→					Text_PreviewName->SetText(FText::FromString(PreviewText));
236→				}
237→			}
238→		}
239→		else
240→		{
241→			// 不匹配
242→			if (Text_PreviewName)
243→			{
244→				Text_PreviewName->SetText(FText::FromString(TEXT("无法合并")));
245→			}
246→			if (Image_PreviewIcon)
247→			{
248→				Image_PreviewIcon->SetRenderOpacity(0.2f);
249→			}
250→		}
251→	}
252→	else
253→	{
254→		// 合成框未满
255→		if (Text_PreviewName)
256→		{
257→			Text_PreviewName->SetText(FText::FromString(TEXT("请选择两个同种同阶单位")));
258→		}
259→		if (Image_PreviewIcon)
260→		{
261→			Image_PreviewIcon->SetRenderOpacity(0.2f);
262→		}
263→	}
264→
265→	if (Button_Merge)
266→	{
267→		Button_Merge->SetIsEnabled(bCanMerge);
268→	}
269→}
270→
271→void ULFPUnitMergeWidget::OnMergeClicked()
272→{
273→	if (!CachedGameInstance || SlotA.bIsEmpty || SlotB.bIsEmpty) return;
274→
275→	bool bSuccess = CachedGameInstance->MergeUnits(
276→		SlotA.bIsParty, SlotA.SlotIndex,
277→		SlotB.bIsParty, SlotB.SlotIndex);
278→
279→	if (bSuccess)
280→	{
281→		UE_LOG(LogTemp, Log, TEXT("升阶 Widget: 合并成功"));
282→	}
283→
284→	ClearSlots();
285→	RefreshUnitIcons();
286→}
287→
288→void ULFPUnitMergeWidget::OnClearClicked()
289→{
290→	ClearSlots();
291→	RefreshUnitIcons();
292→}
293→
294→void ULFPUnitMergeWidget::OnCloseClicked()
295→{
296→	OnClosed.Broadcast();
297→	RemoveFromParent();
298→}
299→
300→void ULFPUnitMergeWidget::UpdateSlotVisual(const FLFPMergeSlotInfo& InSlot, UImage* SlotImage)
301→{
302→	if (!SlotImage) return;
303→
304→	if (InSlot.bIsEmpty)
305→	{
306→		SlotImage->SetRenderOpacity(0.2f);
307→		SlotImage->SetBrushFromTexture(nullptr);
308→	}
309→	else if (CachedRegistry)
310→	{
311→		FLFPUnitRegistryEntry RegEntry;
312→		if (CachedRegistry->FindEntry(InSlot.Unit.TypeID, RegEntry) && RegEntry.Icon)
313→		{
314→			SlotImage->SetBrushFromTexture(RegEntry.Icon);
315→			SlotImage->SetRenderOpacity(1.f);
316→		}
317→	}
318→}
319→
320→FString ULFPUnitMergeWidget::MakeTierStars(int32 Tier) const
321→{
322→	FString Stars;
323→	int32 MaxTier = CachedGameInstance ? CachedGameInstance->MaxUnitTier : 3;
324→	for (int32 i = 0; i < MaxTier; ++i)
325→	{
