	if (!ArrayA.IsValidIndex(SourceAIndex) || !ArrayB.IsValidIndex(SourceBIndex))
	{
		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 无效的槽位索引"));
		return false;
	}

	const FLFPUnitEntry& UnitA = ArrayA[SourceAIndex];
	const FLFPUnitEntry& UnitB = ArrayB[SourceBIndex];

	// 验证匹配条件
	if (UnitA.TypeID != UnitB.TypeID || UnitA.Tier != UnitB.Tier)
	{
		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 单位不匹配 (%s T%d vs %s T%d)"),
			*UnitA.TypeID.ToString(), UnitA.Tier, *UnitB.TypeID.ToString(), UnitB.Tier);
		return false;
	}

	if (UnitA.Tier >= MaxUnitTier)
	{
		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 已达最大阶级 %d"), MaxUnitTier);
		return false;
	}

	// 创建升阶后的新单位
	FLFPUnitEntry NewUnit;
	NewUnit.TypeID = UnitA.TypeID;
	NewUnit.Tier = UnitA.Tier + 1;

	// 移除两个源单位（注意索引偏移：同一数组时先移除大索引）
	if (bSourceAIsParty == bSourceBIsParty)
	{
		// 同一数组，先移除大索引
		int32 First = FMath::Max(SourceAIndex, SourceBIndex);
		int32 Second = FMath::Min(SourceAIndex, SourceBIndex);
		ArrayA.RemoveAt(First);
		ArrayA.RemoveAt(Second);
	}
	else
	{
		// 不同数组，顺序无所谓
		ArrayA.RemoveAt(SourceAIndex);
		ArrayB.RemoveAt(SourceBIndex);
	}

	// 添加新单位
	TryAddUnit(NewUnit);

	UE_LOG(LogTemp, Log, TEXT("升阶成功: %s T%d + T%d → T%d"),
		*NewUnit.TypeID.ToString(), NewUnit.Tier - 1, NewUnit.Tier - 1, NewUnit.Tier);

	return true;
}

