 50→	NewNode->NodeType = NodeType;
 51→	NewNode->AttachToActor(this, FAttachmentTransformRules::KeepWorldTransform);
 52→
 53→	// 应用视觉数据
 54→	if (ULFPWorldNodeDataAsset* VisualData = GetNodeVisualForType(NodeType))
 55→	{
 56→		NewNode->SetNodeVisualData(VisualData);
 57→	}
 58→
 59→	NodeMap.Add(NodeID, NewNode);
 60→
 61→	// 确保邻接表有条目
 62→	if (!AdjacencyList.Contains(NodeID))
 63→	{
 64→		AdjacencyList.Add(NodeID, TSet<int32>());
 65→	}
 66→
 67→	// 更新 ID 计数器
 68→	if (NodeID >= NextNodeID)
 69→	{
 70→		NextNodeID = NodeID + 1;
 71→	}
 72→
 73→	return NewNode;
 74→}
 75→
 76→bool ALFPWorldMapManager::RemoveNode(int32 NodeID)
 77→{
 78→	ALFPWorldMapNode** Found = NodeMap.Find(NodeID);
 79→	if (!Found) return false;
 80→
 81→	// 先移除所有关联边
 82→	if (TArray<FIntPoint>* EdgeKeys = NodeEdgeIndex.Find(NodeID))
 83→	{
 84→		// 复制一份，因为 RemoveEdge 会修改 NodeEdgeIndex
 85→		TArray<FIntPoint> KeysCopy = *EdgeKeys;
 86→		for (const FIntPoint& Key : KeysCopy)
 87→		{
 88→			if (ALFPWorldMapEdge** EdgeFound = EdgeMap.Find(Key))
 89→			{
 90→				int32 OtherID = (Key.X == NodeID) ? Key.Y : Key.X;
 91→				RemoveEdge(NodeID, OtherID);
 92→			}
 93→		}
 94→	}
 95→
 96→	// 销毁 Actor
 97→	if (*Found)
 98→	{
 99→		(*Found)->Destroy();
100→	}
101→
102→	NodeMap.Remove(NodeID);
103→	AdjacencyList.Remove(NodeID);
104→	NodeEdgeIndex.Remove(NodeID);
105→
106→	return true;
107→}
