735→{
736→	for (int32 NodeID : TriggeredNodeIDs)
737→	{
738→		if (ALFPWorldMapNode* Node = GetNode(NodeID))
739→		{
740→			Node->bHasBeenTriggered = true;
741→			Node->UpdateVisualState();
742→		}
743→	}
744→}
