508→ALFPWorldMapManager* ALFPWorldMapPlayerController::GetWorldMapManager() const
509→{
510→	if (!CachedWorldMapManager)
511→	{
512→		TArray<AActor*> Managers;
513→		UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPWorldMapManager::StaticClass(), Managers);
514→		if (Managers.Num() > 0)
515→		{
516→			CachedWorldMapManager = Cast<ALFPWorldMapManager>(Managers[0]);
517→		}
518→	}
519→	return CachedWorldMapManager;
520→}
