522→void ALFPWorldMapPlayerController::OnPawnMoveCompleted()
523→{
524→	// 解绑回调
525→	if (ALFPWorldMapManager* Manager = GetWorldMapManager())
526→	{
527→		if (ALFPWorldMapPawn* MapPawn = Manager->GetPlayerPawn())
528→		{
529→			MapPawn->OnMoveComplete.RemoveDynamic(this, &ALFPWorldMapPlayerController::OnPawnMoveCompleted);
530→		}
531→	}
532→
533→	// 显示新的可达节点
534→	ShowReachableNodes();
535→
536→	// 自动进入目标节点
537→	if (PendingEnterNode)
538→	{
539→		ALFPWorldMapNode* NodeToEnter = PendingEnterNode;
540→		PendingEnterNode = nullptr;
541→		EnterNode(NodeToEnter);
542→	}
543→}
